2974: static void finish_keepalive_ping(
2975:     grpc_core::RefCountedPtr<grpc_chttp2_transport> t,
2976:     grpc_error_handle error) {
2977:   auto* tp = t.get();
2978:   tp->combiner->Run(
2979:       grpc_core::InitTransportClosure<finish_keepalive_ping_locked>(
2980:           std::move(t), &tp->finish_keepalive_ping_locked),
2981:       error);
