2984: static void finish_keepalive_ping_locked(
2985:     grpc_core::RefCountedPtr<grpc_chttp2_transport> t,
2986:     grpc_error_handle error) {
2987:   if (t->keepalive_state == GRPC_CHTTP2_KEEPALIVE_STATE_PINGING) {
2988:     if (error.ok()) {
2989:       if (GRPC_TRACE_FLAG_ENABLED(http) ||
2990:           GRPC_TRACE_FLAG_ENABLED(http_keepalive)) {
2991:         LOG(INFO) << t->peer_string.as_string_view()
2992:                   << ": Finish keepalive ping";
2993:       }
2994:       t->keepalive_state = GRPC_CHTTP2_KEEPALIVE_STATE_WAITING;
2995:       CHECK(t->keepalive_ping_timer_handle == TaskHandle::kInvalid);
2996:       t->keepalive_ping_timer_handle =
2997:           t->event_engine->RunAfter(t->keepalive_time, [t] {
2998:             grpc_core::ApplicationCallbackExecCtx callback_exec_ctx;
2999:             grpc_core::ExecCtx exec_ctx;
3000:             init_keepalive_ping(t);
3001:           });
3002:     }
3003:   }
3004: }
