3006: static void maybe_reset_keepalive_ping_timer_locked(grpc_chttp2_transport* t) {
3007:   if (t->keepalive_ping_timer_handle != TaskHandle::kInvalid &&
3008:       t->event_engine->Cancel(t->keepalive_ping_timer_handle)) {
3009:     // Cancel succeeds, resets the keepalive ping timer. Note that we don't
3010:     // need to Ref or Unref here since we still hold the Ref.
3011:     if (GRPC_TRACE_FLAG_ENABLED(http) ||
3012:         GRPC_TRACE_FLAG_ENABLED(http_keepalive)) {
3013:       LOG(INFO) << t->peer_string.as_string_view()
3014:                 << ": Keepalive ping cancelled. Resetting timer.";
3015:     }
3016:     t->keepalive_ping_timer_handle =
3017:         t->event_engine->RunAfter(t->keepalive_time, [t = t->Ref()]() mutable {
3018:           grpc_core::ApplicationCallbackExecCtx callback_exec_ctx;
3019:           grpc_core::ExecCtx exec_ctx;
3020:           init_keepalive_ping(std::move(t));
3021:         });
3022:   }
3023: }
