ait == other.wait;\n49:     }\n50:   };\n51:   using RequestSendPingResult =\n52:       absl::variant\u003cSendGranted, TooManyRecentPings, TooSoon\u003e;\n53: \n54:   // Request that one ping be sent.\n55:   // Returns:\n56:   //  - SendGranted if a ping can be sent.\n57:   //  - TooManyRecentPings if too many pings have been sent recently and we\n58:   //    should wait for some future write.\n59:   //  - TooSoon if we should wait for some time before sending the ping.\n60:   RequestSendPingResult RequestSendPing(Duration next_allowed_ping_interval,\n61:                                         size_t inflight_pings) const;\n62:   // Notify the policy that one ping has been sent.\n63:   void SentPing();\n64:   // Notify the policy that some data has been sent and so we should no longer\n65:   // block pings on that basis.\n66:   void ResetPingsBeforeDataRequired();\n67:   // Notify the policy that we've received some data.\n68:   void ReceivedDataFrame();\n69:   std::string GetDebugString() const;\n70: \n71:   int TestOnlyMaxPingsWithoutData() const {\n72:     return max_pings_without_data_sent_;\n73:   }\n74: \n75:  private:\n76:   const int max_pings_without_data_sent_;\n77:   const int max_inflight_pings_;\n78:   int pings_before_data_sending_required_ = 0;\n79:   Timestamp last_ping_sent_time_ = Timestamp::InfPast();\n80: };\n81: \n82: std::ostream\u0026 operator\u003c\u003c(std::ostream\u0026 out,\n83:                          const Chttp2PingRatePolicy::RequestSendPingResult\u0026 r);\n84: \n85: }  // namespace grpc_core\n86: \n87: #endif  // GRPC_SRC_CORE_EXT_TRANSPORT_CHTTP2_TRANSPORT_PING_RATE_POLICY_H\n88: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/grpc--v1.68.0@5f9b92d127d438c80fa41db9d0e65adc79dc2e9e/-/blob/src/core/ext/transport/chttp2/transport/ping_rate_policy.h"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: // Copyright 2023 gRPC authors.
